**Verilator:** 5.046

## What happens

When a combinatorial loop contains a bistable node — where both `{A=0, B=1}` and `{A=1, B=0}` are valid — Verilator's single-pass evaluation with `-Wno-UNOPTFLAT` can lock onto the wrong stable state. If that node gates a multi-cycle FSM handshake, the FSM never clears and the simulation deadlocks permanently.

Found while running RISC-V ACT4 certification tests against CV32E40P with FPU enabled (cv32e40p-dv](https://github.com/karabambus/cv32e40p-dv)). `fdiv`/`fsqrt` tests hang indefinitely in Verilator; same tests pass in Questa.

## Reproducer

```systemverilog
// HANGS: apu_stall depends on id_ready (bistable loop)
// When rvalid=1 and apu_active_q=1, two stable states exist:
//   {id_ready=0, apu_stall=1}  <- wrong, Verilator picks this (old id_ready=0)
//   {id_ready=1, apu_stall=0}  <- correct
// done is never asserted; apu_active_q never clears; deadlock.
module apu_loop_hang (
  input  logic       clk, rst_n, instr_valid,
  input  logic [4:0] apu_latency,
  output logic       done
);
  logic [4:0] cnt_q;
  logic       apu_active_q, id_ready, apu_stall, apu_rvalid;

  assign apu_rvalid = apu_active_q && (cnt_q == '0);
  assign apu_stall  = apu_active_q && !(apu_rvalid && id_ready); // depends on id_ready
  assign id_ready   = !apu_stall;  // UNOPTFLAT: loop closes here
  assign done       = apu_rvalid && id_ready;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin apu_active_q <= 0; cnt_q <= '0; end
    else begin
      if (instr_valid && id_ready && !apu_active_q) begin
        apu_active_q <= 1; cnt_q <= apu_latency;
      end
      if (apu_active_q && cnt_q > 0) cnt_q <= cnt_q - 1;
      if (done) apu_active_q <= 0;
    end
  end
endmodule

// PASSES: apu_stall does not depend on id_ready — no bistable loop
// When rvalid=1, apu_stall=0 unconditionally regardless of evaluation order.
module apu_loop_fixed (
  input  logic       clk, rst_n, instr_valid,
  input  logic [4:0] apu_latency,
  output logic       done
);
  logic [4:0] cnt_q;
  logic       apu_active_q, id_ready, apu_stall, apu_rvalid;

  assign apu_rvalid = apu_active_q && (cnt_q == '0);
  assign apu_stall  = apu_active_q && !apu_rvalid; // no id_ready term
  assign id_ready   = !apu_stall;
  assign done       = apu_rvalid && id_ready;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin apu_active_q <= 0; cnt_q <= '0; end
    else begin
      if (instr_valid && id_ready && !apu_active_q) begin
        apu_active_q <= 1; cnt_q <= apu_latency;
      end
      if (apu_active_q && cnt_q > 0) cnt_q <= cnt_q - 1;
      if (done) apu_active_q <= 0;
    end
  end
endmodule

module tb;
  logic clk = 0, rst_n = 0;
  always #5 clk = ~clk;

  logic done_h2, done_h25, done_f2, done_f25;
  apu_loop_hang  h2  (.clk(clk),.rst_n(rst_n),.instr_valid(1),.apu_latency(5'd2), .done(done_h2));
  apu_loop_hang  h25 (.clk(clk),.rst_n(rst_n),.instr_valid(1),.apu_latency(5'd25),.done(done_h25));
  apu_loop_fixed f2  (.clk(clk),.rst_n(rst_n),.instr_valid(1),.apu_latency(5'd2), .done(done_f2));
  apu_loop_fixed f25 (.clk(clk),.rst_n(rst_n),.instr_valid(1),.apu_latency(5'd25),.done(done_f25));

  int cycle; logic sh2,sh25,sf2,sf25;
  initial begin
    rst_n=0; cycle=0; sh2=0; sh25=0; sf2=0; sf25=0;
    repeat(2) @(posedge clk); rst_n=1;
    repeat(200) begin
      @(posedge clk); #1; cycle++;
      if(done_h2  && !sh2)  begin $display("[%0d] HANG  lat=2  done",cycle);  sh2=1;  end
      if(done_h25 && !sh25) begin $display("[%0d] HANG  lat=25 done",cycle);  sh25=1; end
      if(done_f2  && !sf2)  begin $display("[%0d] FIXED lat=2  done",cycle);  sf2=1;  end
      if(done_f25 && !sf25) begin $display("[%0d] FIXED lat=25 done",cycle);  sf25=1; end
      if(sh2&&sh25&&sf2&&sf25) break;
    end
    $display("HANG  lat=2 : %s", sh2  ? "done":"DEADLOCK");
    $display("HANG  lat=25: %s", sh25 ? "done":"DEADLOCK");
    $display("FIXED lat=2 : %s", sf2  ? "done":"DEADLOCK");
    $display("FIXED lat=25: %s", sf25 ? "done":"DEADLOCK");
    $finish;
  end
endmodule
```

**Build and run:**
```
verilator --binary -sv --top tb repro.sv -Wno-UNOPTFLAT && ./obj_dir/Vtb
```

**Output:**
```
[2]  FIXED lat=2  done
[25] FIXED lat=25 done
HANG  lat=2 : DEADLOCK
HANG  lat=25: DEADLOCK
FIXED lat=2 : done
FIXED lat=25: done
```
## Manual gap

The manual says UNOPTFLAT "simulates correctly but slowly."

